import sys
sys.path.insert(0, '/tmp/jt')
from jinja2 import Environment, FileSystemLoader, DictLoader, PrefixLoader, ChoiceLoader
from jinja2.exceptions import TemplateNotFound

def alias(t):
    return {'home': 'index.html'}.get(t, t)

fs = FileSystemLoader('/tmp/jt/templates', path_transform=alias)
env = Environment(loader=fs)
print('FS:', env.get_template('home').render())

try:
    env.get_template('missing')
except TemplateNotFound as e:
    print('FS not found name:', e.name)

# PrefixLoader test - transform applied at top level before split
def prefix_transform(t):
    return t.replace('legacy/', 'app1/')

p = PrefixLoader({'app1': DictLoader({'x.html': 'APP1_X'})}, path_transform=prefix_transform)
env2 = Environment(loader=p)
print('Prefix:', env2.get_template('legacy/x.html').render())

try:
    env2.get_template('legacy/missing.html')
except TemplateNotFound as e:
    print('Prefix not found name:', e.name)

# ChoiceLoader
def choice_transform(t):
    return t.lstrip('/')

c = ChoiceLoader([DictLoader({'y.html': 'Y_CONTENT'})], path_transform=choice_transform)
env3 = Environment(loader=c)
print('Choice:', env3.get_template('/y.html').render())
"
